const transCode = `
addHandler("transform", (request, context) => {
  const body = request.body;
  if (!body || !body.data || !body.data.object) {
    return null;
  }
  const obj = body.data.object;
  if (typeof obj.amount !== 'number' || obj.amount < 100) {
    return null;
